import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useToast } from '../context/ToastContext';
import api from '../utils/api';

export default function JobBoardPage() {
  const [jobs,     setJobs]     = useState([]);
  const [allJobs,  setAllJobs]  = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [scoring,  setScoring]  = useState(false);
  const [search,   setSearch]   = useState('');
  const [filter,   setFilter]   = useState('all');
  const [selected, setSelected] = useState(null);
  const [applying, setApplying] = useState(false);
  const { showToast } = useToast();
  const navigate = useNavigate();

  useEffect(() => { fetchJobs(); }, []);

  const fetchJobs = async () => {
    setLoading(true);
    try {
      const res = await api.get('/jobs');
      setAllJobs(res.data.data || []);
      setJobs(res.data.data || []);
      // Try to get ATS scores
      fetchScores();
    } catch (_) {}
    setLoading(false);
  };

  const fetchScores = async () => {
    setScoring(true);
    try {
      const res = await api.get('/analyzer/jobboard');
      const scoreMap = {};
      res.data.data.forEach(j => { scoreMap[j.jobId] = j; });
      setAllJobs(prev => prev.map(j => ({ ...j, atsScore: scoreMap[j._id]?.atsScore, matchedSkills: scoreMap[j._id]?.matchedSkills, missingSkills: scoreMap[j._id]?.missingSkills })));
      setJobs(prev => prev.map(j => ({ ...j, atsScore: scoreMap[j._id]?.atsScore, matchedSkills: scoreMap[j._id]?.matchedSkills, missingSkills: scoreMap[j._id]?.missingSkills })));
    } catch (_) {}
    setScoring(false);
  };

  const applyForJob = async (jobId) => {
    setApplying(true);
    try {
      const res = await api.post(`/applications/${jobId}`);
      showToast(`Applied! ATS Score: ${res.data.data.atsScore}`, 'success');
      setSelected(prev => prev ? { ...prev, applied: true } : prev);
    } catch (err) {
      const msg = err.response?.data?.message || 'Application failed';
      if (msg.includes('resume')) {
        showToast('Upload your resume first!', 'error');
        navigate('/resume');
      } else {
        showToast(msg, 'error');
      }
    } finally { setApplying(false); }
  };

  useEffect(() => {
    let filtered = allJobs;
    if (search) filtered = filtered.filter(j =>
      j.title.toLowerCase().includes(search.toLowerCase()) ||
      j.company.toLowerCase().includes(search.toLowerCase())
    );
    if (filter === 'remote')    filtered = filtered.filter(j => j.location?.toLowerCase().includes('remote'));
    if (filter === 'fulltime')  filtered = filtered.filter(j => j.type === 'full-time');
    if (filter === 'contract')  filtered = filtered.filter(j => j.type === 'contract');
    if (filter === 'highscore') filtered = [...filtered].sort((a,b) => (b.atsScore||0) - (a.atsScore||0));
    setJobs(filtered);
  }, [search, filter, allJobs]);

  const scoreClass = (s) => !s ? 'score-mid' : s >= 75 ? 'score-high' : s >= 50 ? 'score-mid' : 'score-low';

  if (loading) return <div className="loading-screen"><div className="spinner" /></div>;

  return (
    <div className="page-wrap">
      <div className="flex items-center justify-between mb-4">
        <div className="page-header" style={{ marginBottom: 0 }}>
          <div className="page-title">Job Board</div>
          <div className="page-subtitle">
            {scoring ? '⚡ Calculating your ATS scores...' : `${jobs.length} jobs available — sorted by best match`}
          </div>
        </div>
      </div>

      {/* Search & Filters */}
      <div className="search-row">
        <div className="search-box">
          <span style={{ color: 'var(--text3)' }}>🔍</span>
          <input placeholder="Search roles, companies..." value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        {['all','remote','fulltime','contract','highscore'].map(f => (
          <button key={f} className={`chip ${filter === f ? 'active' : ''}`} onClick={() => setFilter(f)}>
            {f === 'all' ? 'All' : f === 'remote' ? 'Remote' : f === 'fulltime' ? 'Full-time' : f === 'contract' ? 'Contract' : '⭐ Best Match'}
          </button>
        ))}
      </div>

      {jobs.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">💼</div>
          <div className="empty-title">No jobs found</div>
          <div className="empty-sub">Try a different search or filter</div>
        </div>
      ) : (
        <div style={{ display: 'grid', gap: 12 }}>
          {jobs.map(job => (
            <div key={job._id} className={`job-card ${selected?._id === job._id ? 'selected' : ''}`}
              onClick={() => setSelected(job)}>
              <div className="flex items-center justify-between mb-1">
                <div className="job-title-text">{job.title}</div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                  {scoring
                    ? <span style={{ fontSize: 12, color: 'var(--text3)' }}>Calculating...</span>
                    : job.atsScore !== undefined
                      ? <span className={`score-pill ${scoreClass(job.atsScore)}`}>{job.atsScore}% match</span>
                      : null
                  }
                  {job.salaryMin && (
                    <span className="tag tag-gray">${Math.round(job.salaryMin/1000)}k–${Math.round(job.salaryMax/1000)}k</span>
                  )}
                </div>
              </div>
              <div className="job-meta">
                <span>🏢 {job.company}</span>
                <span>📍 {job.location}</span>
                <span>⏱ {job.type}</span>
                <span>🗓 {new Date(job.createdAt).toLocaleDateString()}</span>
              </div>
              {job.requiredSkills?.length > 0 && (
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginTop: 10 }}>
                  {job.requiredSkills.slice(0, 5).map((s, i) => {
                    const matched = job.matchedSkills?.includes(s.toLowerCase());
                    return <span key={i} className={`tag ${matched ? 'tag-green' : 'tag-red'}`}>{s}</span>;
                  })}
                </div>
              )}
              {selected?._id === job._id && (
                <div style={{ marginTop: '1rem', display: 'flex', gap: 8 }} onClick={e => e.stopPropagation()}>
                  <button className="btn btn-primary btn-sm" onClick={() => applyForJob(job._id)} disabled={applying}>
                    {applying ? <span className="spinner" /> : '📤 Apply Now'}
                  </button>
                  <button className="btn btn-secondary btn-sm" onClick={() => navigate('/analyzer')}>
                    ⚡ Full Analysis
                  </button>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
